// src/App.js
import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import Home from './pages/Home';
import PandalDetails from './pages/PandalDetails';
import MapView from './pages/MapView';
import Favorites from './pages/Favorites';
import Search from './pages/Search';
import About from './pages/About';
import './App.css';

function App() {
  const [pandals, setPandals] = useState([]);
  const [loading, setLoading] = useState(true);
  const [favorites, setFavorites] = useState([]);

  useEffect(() => {
    // Load favorites from localStorage
    const storedFavorites = localStorage.getItem('manchitra-favorites');
    if (storedFavorites) {
      setFavorites(JSON.parse(storedFavorites));
    }

    // Fetch pandal data
    fetchPandals();
  }, []);

  const fetchPandals = async () => {
    try {
      setLoading(true);
      // In a real app, this would be an actual API endpoint
      const response = await fetch('/api/pandals');
      const data = await response.json();
      setPandals(data);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching pandal data:', error);
      setLoading(false);
    }
  };

  const toggleFavorite = (pandalId) => {
    let newFavorites;
    if (favorites.includes(pandalId)) {
      newFavorites = favorites.filter(id => id !== pandalId);
    } else {
      newFavorites = [...favorites, pandalId];
    }
    setFavorites(newFavorites);
    localStorage.setItem('manchitra-favorites', JSON.stringify(newFavorites));
  };

  return (
    <Router>
      <div className="app">
        <Navbar />
        <main className="content">
          <Routes>
            <Route path="/" element={<Home pandals={pandals} loading={loading} favorites={favorites} toggleFavorite={toggleFavorite} />} />
            <Route path="/pandal/:id" element={<PandalDetails pandals={pandals} favorites={favorites} toggleFavorite={toggleFavorite} />} />
            <Route path="/map" element={<MapView pandals={pandals} />} />
            <Route path="/favorites" element={<Favorites pandals={pandals} favorites={favorites} toggleFavorite={toggleFavorite} />} />
            <Route path="/search" element={<Search pandals={pandals} favorites={favorites} toggleFavorite={toggleFavorite} />} />
            <Route path="/about" element={<About />} />
          </Routes>
        </main>
      </div>
    </Router>
  );
}

export default App;
